class IndentationRuleLambdaTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `test lambda parameter indentation with intellij_idea code style`() {
        val code = """
            fun combine(a: Any, b: Any, c: (Any, Any) -> Unit) {
              c(a, b)
            }

